diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..9b67419aee6c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4516,6 +4516,29 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
     std::swap(Op0, Op1);
     Pred = ICmpInst::getSwappedPredicate(Pred);
   }
+
+  // icmp (xor (xor A, -1), B), (xor C, -1) -> icmp swapped_pred (xor A, B), C
+  // This is based on the identity: (~A ^ B) < ~C  <=>  (A ^ B) > C
+  // because ~A ^ B = ~(A ^ B) and ~X < ~Y <=> X > Y
+  Value *B, *X, *InnerA, *InnerC;
+  if (match(Op0, m_c_Xor(m_Value(X), m_Value(B)))) {
+    // Check if X is xor A, -1 and Op1 is xor C, -1
+    if (match(X, m_c_Xor(m_Value(InnerA), m_AllOnes())) &&
+        match(Op1, m_c_Xor(m_Value(InnerC), m_AllOnes()))) {
+      // Op0 = (A ^ -1) ^ B = ~A ^ B = ~(A ^ B)
+      // Op1 = C ^ -1 = ~C
+      // We want: icmp Pred (~(A ^ B)), ~C -> icmp swapped_pred (A ^ B), C
+      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred),
+                          IC.Builder.CreateXor(InnerA, B), InnerC);
+    }
+    // Check the commutative case: Op0 = B ^ (A ^ -1)
+    if (match(B, m_c_Xor(m_Value(InnerA), m_AllOnes())) &&
+        match(Op1, m_c_Xor(m_Value(InnerC), m_AllOnes()))) {
+      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred),
+                          IC.Builder.CreateXor(InnerA, X), InnerC);
+    }
+  }
+
   if (!match(Op0, m_c_Xor(m_Specific(Op1), m_Value(A))))
     return nullptr;

log.source_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %xor1 = xor i32 %y, -1
  %xor2 = xor i32 %xor1, %x
  %r = icmp sle i32 %xor2, %xor1
  ret i1 %r
}

log.expect_optimized_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %1 = xor i32 %y, %x
  %r = icmp sge i32 %1, %y
  ret i1 %r
}

